#!/usr/bin/env python3

# Compute the first 20 Fibonacci numbers
n = 20
fibonacci = []

for i in range(n):
    if i == 0:
        fibonacci.append(0)
    elif i == 1:
        fibonacci.append(1)
    else:
        fibonacci.append(fibonacci[i-1] + fibonacci[i-2])

# Print as comma-separated list
print(','.join(map(str, fibonacci)))
